// 1. Security headers (helmet sets ~15 protective headers automatically)
app.use(helmet());

// 2. Parse JSON bodies with a size limit to prevent payload attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// 3. Rate limiting — 100 requests per 15 minutes per IP
