  res.json([
    { id: 1, name: 'Alice' },  // email omitted from unauthenticated views
    { id: 2, name: 'Bob' },
  ]);
});

// 6. 404 handler for unknown routes
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// 7. Global error handler — catches errors thrown/passed in any route
app.use((err, req, res, next) => {
