Here's a thorough review of `app.js` with security-focused improvements for error handling and input validation:

---

## Current Issues

1. **No body parsing middleware** — The app has no `express.json()` or `express.urlencoded()` middleware, so POST/PUT requests with bodies would silently fail.
2. **No input validation** — Query parameters (e.g., `?id=`, `?limit=`) are accepted but never validated or sanitized.
3. **No error handling middleware** — Unhandled errors would expose stack traces to clients in development, or crash silently in production.
4. **No rate limiting** — All endpoints are open to abuse.
5. **No security headers** — Missing headers like `X-Content-Type-Options`, `X-Frame-Options`, etc.
6. **Hardcoded port** — `3000` is hardcoded rather than read from the environment.
7. **`/users` leaks all user data** — No pagination, authentication, or field filtering.

---

## Suggested Improvements

```js
'use strict';

const express = require('express');
const app = express();

// --- Security headers (use helmet in production) ---
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// --- Body parsing with size limits ---
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Helpers ---
const SAFE_INT_REGEX = /^\d+$/;

function isPositiveInt(value) {
  return typeof value === 'string' && SAFE_INT_REGEX.test(value) && parseInt(value, 10) > 0;
}

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    const { limit = '10', offset = '0' } = req.query;

    // Input validation
    if (!isPositiveInt(limit) || parseInt(limit, 10) > 100) {
      return res.status(400).json({ error: '`limit` must be a positive integer no greater than 100.' });
    }
    if (!/^\d+$/.test(offset)) {
      return res.status(400).json({ error: '`offset` must be a non-negative integer.' });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Return only safe, expected fields — never spread raw DB objects
    const safeUsers = users.map(({ id, name, email }) => ({ id, name, email }));

    res.json({ data: safeUsers, total: safeUsers.length });
  } catch (err) {
    next(err); // Forward to centralized error handler
  }
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Centralized error handler ---
app.use((err, req, res, _next) => {
  // Never expose internal details to the client
  console.error('[ERROR]', err);
  const statusCode = err.status || err.statusCode || 500;
  res.status(statusCode).json({
    error: statusCode < 500 ? err.message : 'An internal error occurred.',
  });
});

// --- Start server ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

## Summary of Changes

| Area | What Changed | Why |
|---|---|---|
