app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal server error' : err.message
  });
});
```

### 6. 🔍 Add Input Validation for Query Parameters
The `/users` route accepts query strings with no validation. If it ever filters by input, this is an injection risk.
```js
const { query, validationResult } = require('express-validator');

app.get('/users', [
  query('id').optional().isInt({ min: 1 }).toInt(),
  query('name').optional().trim().escape().isLength({ max: 100 }),
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) return res.status(400).json({ errors: errors.array() });
  // ... route logic
});
```

### 7. 🌐 Restrict CORS (if applicable)
If this API is consumed by a frontend, lock down cross-origin access:
```js
const cors = require('cors');
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || 'https://yourdomain.com' }));
```

### 8. 📝 Structured Logging
Replace `console.log` with a structured logger for better observability and to avoid leaking sensitive data in production:
```js
const pino = require('pino');
const logger = pino();
// Replace: console.log('Server running on port 3000');
logger.info('Server running on port 3000');
```

### 9. ⚙️ Configurable Port via Environment Variable
Hardcoding port `3000` is inflexible and can be a misconfiguration risk in production:
```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => logger.info(`Server running on port ${PORT}`));
```

